var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"결국 다시 부두로 돌아왔네.","JPN":"結局また港に戻ってきてしまったね。","ENG":"I guess we're back at the docks.","TWN":"結果我們又回到碼頭這裡了。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬- 이거지. 이 음습한 골목의 짠내가 그리웠어.","JPN":"きゃーこれよ。この薄暗い路地の磯臭い感じが恋しかったよ。","ENG":"Whew! This is it. I missed the salty scent of this sketchy alley.","TWN":"嗯～就是這個味道。潮濕的小巷子裡特有的海水鹹味。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"셰프! 여기 한 그릇 더!","JPN":"料理長！　おかわりください！","ENG":"Chef! Another one!","TWN":"老闆，我還要再一碗！"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHEF_FRONTBAY_NULL_WHALE","text":{"KOREA":"너희들… 고작 주방일 세 시간 도와준 걸로 너무 많이 먹는 거 아니냐?","JPN":"あなたたち……厨房の仕事3時間しかしてないくせに、食べ過ぎじゃない？","ENG":"Don't you think you're eating more than you've worked for? You only helped in the kitchen for three hours.","TWN":"你們三個…才在廚房幫忙三個小時而已，會不會吃得有點多？"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"셰프도 참-! 파리 날리는 불경기에 음식 먹어주는 손님이 있는 게 어디에요!","JPN":"まったくもうー！　客もない不景気には食べてくれるお客がいるだけで良いものなんですよ！","ENG":"Oh, Chef! You should be glad you have customers during this recession!","TWN":"哎呀！現在不景氣，很多店家都在養蒼蠅，有客人來捧場你要開心欸！"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHEF_FRONTBAY_NULL_WHALE","text":{"KOREA":"별 수 있나? 여기서 술을 사는 손님 대부분은 헌터들이었는데, 격벽이 봉쇄되면서 바다로 나갈 길이 닫혔으니.","JPN":"仕方ないだろう？　ここで酒を買う客はほとんどがハンターだったのに、隔壁が封鎖されて海に出られなくなったから。","ENG":"Well, I don't have much choice, do I? Most of the customers who drank here were hunters. But with the bulwark closed, there's no way to the sea.","TWN":"有什麼辦法？會在這裡喝酒的顧客大部分都是獵人，隔離牆被封起來後，出海的路也隨之被封死。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_IDLE","text":{"KOREA":"케케케, 우리라도 바다에 나가 줄까?","JPN":"けけけ、俺らでも海に出てやろうか？","ENG":"Keh heh heh, you want us to go out to sea for you?","TWN":"呵呵呵，你想要我們出海嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_IDLE","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_IDLE","text":{"KOREA":"겁쟁이 헌터들과 다르게 우리 같은 해적들은 관리국에서 뭐라 하건 상관하지 않는다고.","JPN":"臆病者のハンターとは違って俺ら海賊は管理局が何て言おうが気にしないから。","ENG":"Unlike those cowardly hunters, we pirates don't care what the Administration says.","TWN":"我們海盜才不像獵人一樣膽小，我們不在乎管理局說什麼。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_IDLE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHEF_FRONTBAY_NULL_WHALE","text":{"KOREA":"자넨 밀린 외상값이나 갚아, 터커.","JPN":"お前は溜まっている付けを返せ、ターカー。","ENG":"Why don't you pay your tab first, Tucker?","TWN":"你先把賒的賬給結清再說吧，塔克。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_IDLE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_IDLE","text":{"KOREA":"맨날 나한테만 못되게 굴어.","JPN":"いつも俺にばっか厳しんだよな。","ENG":"You're always so mean to me.","TWN":"你就只會欺負我。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_IDLE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHEF_FRONTBAY_NULL_WHALE","text":{"KOREA":"애초에 너희 해적들은 왜 늘 그 모양이냐? 허구한 날 헌터들에게 시비나 걸고 말이지.","JPN":"そもそもお前ら海賊は何でいつもそうなんだ？　ハンターに喧嘩ばかり売ってさ。","ENG":"What's wrong with you pirates, anyway? You're always picking fights with those hunters.","TWN":"你們海盜怎麼都這副德行，成天沒事就去招惹獵人。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_IDLE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHEF_FRONTBAY_NULL_WHALE","text":{"KOREA":"덕분에 니들이 싸움으로 부숴먹은 가게 자산만 얼만지 알아?","JPN":"そのせいでお前らがぶっ壊した店の財産がいくらだと思うんだ！","ENG":"Do you know how much money it cost me to repair everything that broke in your fights?","TWN":"你知道，因為你們打架鬥毆我的店損失多少嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_IDLE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"쿨럭, 쿨럭…!","JPN":"ゲホッ、ゲホッ……！","ENG":"*Cough!* *Cough!*","TWN":"咳咳，咳咳…！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"소냐…! 저, 모, 목에 닭뼈가…!","JPN":"ソーニャ……！　私、く、首に鳥の骨が……！","ENG":"Sonya...! Ch-chicken bone, in my th-throat...!","TWN":"索妮雅…！那個，脖子上有雞骨頭…！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"쉿, 조용히 해.","JPN":"しっ、黙って。","ENG":"Shh. Be quiet.","TWN":"噓，安靜。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"흥, 내가 어렸을 땐 프론트베이엔 관리국도, 헌터도 없었어.","JPN":"ふん、俺が子どもの頃はフロントベイには管理局もハンターもなかったんだ。","ENG":"Hmph. When I was young, there was no Administration or hunters in Front Bay.","TWN":"哼，我小時候前灣還沒有管理局，也沒有獵人。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"마을에 침식체가 들이닥치면 항상 에이버리가 이끄는 해적단이 우릴 구해줬다고.","JPN":"村に侵食体が入ってくるといつもエイバリーが率いる海賊団が俺たちを救ってくれたんだ。","ENG":"When C.O.s attacked the town, Avery's crew was always there to save us.","TWN":"每當有侵蝕體出現時，艾維利都會帶著海盜來救我們。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHEF_FRONTBAY_NULL_WHALE","text":{"KOREA":"그래, 대정화전쟁 후로 법 없는 세상이 왔을 땐 해적들이 우릴 지켜줬었지.","JPN":"そうだ、大浄化戦争の後、法のない世界が来た時、海賊が俺らを救ってくれた。","ENG":"Yeah, pirates were the ones who protected us in the days of anarchy after the Grand Purification War.","TWN":"沒錯，大淨化戰爭後世界陷入一片混亂，是海盜在保護我們的。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHEF_FRONTBAY_NULL_WHALE","text":{"KOREA":"하지만 세상이 변했어. 지금 프론트베이를 지켜주고 있는 건 해적이 아니라 관리국이라고.","JPN":"しかし、今は世の中が変わったんだ。今フロントベイを守っているのは海賊ではなく管理局だぞ。","ENG":"But times have changed. The Administration is the one protecting Front Bay, not pirates.","TWN":"後來世界豬羊變色，現在守護前灣的不是海盜，而是管理局。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"관리국이 멋대로 바다를 통제하는 바람에 섬에 살던 우리 가족은 고향에서 쫓겨났고, 어부였던 아버진 일자릴 잃었어!","JPN":"管理局が勝手に海を統制したせいで島に住んでいた俺たち家族は故郷から追い出されたし、漁師だった父は仕事を失った！","ENG":"Once the Administration started controlling the sea, my family was kicked out of our island home, and my fisherman father lost his job!","TWN":"管理局擅自介入管理大海，害我原本住在島上的家人被迫離開家鄉，原本是漁民的父親也因此失業！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};